import React from 'react';
import styled from 'styled-components';

const HeroSection = styled.section`
  padding: 4rem 2rem;
  text-align: center;
  background: #f8f9fa;
`;

const ContentWrapper = styled.div`
  max-width: 800px;
  margin: 0 auto;
`;

const ProfilePhoto = styled.img`
  width: 150px;
  height: 150px;
  border-radius: 50%;
  margin: 0 auto 1.5rem;
  display: block;
  object-fit: cover;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
`;

const Eyebrow = styled.p`
  font-size: 1rem;
  color: #667eea;
  font-weight: 600;
  text-transform: uppercase;
  margin-bottom: 0.5rem;
`;

const MainHeading = styled.h1`
  font-size: 2.5rem;
  color: #1a1a1a;
  margin-bottom: 1rem;
`;

const Subtitle = styled.p`
  font-size: 1.2rem;
  color: #546e7a;
  line-height: 1.6;
  margin-bottom: 2rem;
`;

const CTAContainer = styled.div`
  display: flex;
  justify-content: center;
  gap: 1rem;
`;

const PrimaryButton = styled.a`
  padding: 0.75rem 1.5rem;
  background: #667eea;
  color: #fff;
  text-decoration: none;
  border-radius: 8px;
  font-weight: 600;
  transition: background 0.3s ease;

  &:hover {
    background: #5a67d8;
  }
`;

const SecondaryButton = styled.a`
  padding: 0.75rem 1.5rem;
  background: #e2e8f0;
  color: #1a202c;
  text-decoration: none;
  border-radius: 8px;
  font-weight: 600;
  transition: background 0.3s ease;

  &:hover {
    background: #cbd5e0;
  }
`;

const SpecialtiesSection = styled.section`
  padding: 4rem 2rem;
  background: #ffffff;
`;

const SpecialtiesWrapper = styled.div`
  max-width: 1000px;
  margin: 0 auto;
`;

const SectionTitle = styled.h2`
  font-size: 2rem;
  color: #1a1a1a;
  text-align: center;
  margin-bottom: 2rem;
`;

const SpecialtiesGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
`;

const SpecialtyCard = styled.div`
  padding: 2rem;
  background: #f8f9fa;
  border-radius: 12px;
  border: 1px solid #e0e0e0;
  transition: all 0.3s ease;

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
    border-color: #667eea;
  }
`;

const SpecialtyIcon = styled.div`
  font-size: 2.5rem;
  margin-bottom: 1rem;
`;

const SpecialtyTitle = styled.h3`
  font-size: 1.3rem;
  font-weight: 600;
  color: #1a1a1a;
  margin-bottom: 0.75rem;
`;

const SpecialtyDescription = styled.p`
  font-size: 0.95rem;
  color: #546e7a;
  line-height: 1.6;
`;

const HomePage = () => (
  <>
    <HeroSection>
      <ContentWrapper>
        <ProfilePhoto src="/path-to-photo.jpg" alt="Joël Tiogo" />
        <Eyebrow>Business Development Manager & AI Consultant</Eyebrow>
        <MainHeading>
          Joël Tiogo
        </MainHeading>
        <Subtitle>
          A dynamic leader with an MBA and entrepreneurial experience, driving growth, innovation, and strategic impact across industries like automotive, sustainability, and enterprise technologies.
        </Subtitle>
        <CTAContainer>
          <PrimaryButton href="/about">View Experience</PrimaryButton>
          <SecondaryButton href="mailto:tiogojoel@gmail.com">Get in Touch</SecondaryButton>
        </CTAContainer>
      </ContentWrapper>
    </HeroSection>

    <SpecialtiesSection>
      <SpecialtiesWrapper>
        <SectionTitle>Core Expertise</SectionTitle>
        <SpecialtiesGrid>
          <SpecialtyCard>
            <SpecialtyIcon>📊</SpecialtyIcon>
            <SpecialtyTitle>Strategic Leadership</SpecialtyTitle>
            <SpecialtyDescription>
              Leveraging diverse leadership experience to guide cross-functional teams, foster innovation, and deliver measurable results in dynamic industries.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🤝</SpecialtyIcon>
            <SpecialtyTitle>Stakeholder Management</SpecialtyTitle>
            <SpecialtyDescription>
              Collaborating with clients, partners, and teams to align business objectives, build trust, and deliver impactful solutions.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🌍</SpecialtyIcon>
            <SpecialtyTitle>Sustainability & ESG</SpecialtyTitle>
            <SpecialtyDescription>
              Driving sustainability initiatives and ESG compliance through data-driven insights and innovative strategies.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🚗</SpecialtyIcon>
            <SpecialtyTitle>Automotive Analytics</SpecialtyTitle>
            <SpecialtyDescription>
              Delivering data-driven solutions for OEMs and Tier 1 suppliers, focusing on predictive maintenance, fleet optimization, and connected vehicles.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🤖</SpecialtyIcon>
            <SpecialtyTitle>AI-Powered Solutions</SpecialtyTitle>
            <SpecialtyDescription>
              Designing and implementing AI/ML solutions to solve complex business challenges and enhance decision-making processes.
            </SpecialtyDescription>
          </SpecialtyCard>
        </SpecialtiesGrid>
      </SpecialtiesWrapper>
    </SpecialtiesSection>
  </>
);

export default HomePage;
